    target_audience: textCell(fields['目标人群']), user_persona: textCell(fields['使用者画像']), buyer_persona: textCell(fields['购买者画像']), visceral_pain_points: textCell(fields['刺骨痛点']), emotional_triggers: textCell(fields['情绪触发器']), buyer_objections: textCell(fields['购买阻力']),
    visual_hook_elements: textCell(fields['视觉抓手']), offer_and_guarantee: textCell(fields['优惠促销保障']), risk_constraints: textCell(fields['禁说内容风险点']), manual_notes: textCell(fields['用户手动备注'])
  };
}
function chainText(input) { return String(input?.text || input?.output || input?.response || '').trim(); }
async function sleep(ms) { return new Promise((resolve) => setTimeout(resolve, ms)); }
function parseJson(input) {
  if (input && typeof input === 'object' && !input.text && !input.output) return input;
  const raw = String(input?.text || input?.output || input?.response || '');
  const cleaned = raw.replace(/^\s*\`\`\`(?:json)?/i, '').replace(/\`\`\`\s*$/i, '').trim();
  try { return JSON.parse(cleaned); } catch {}
  const first = cleaned.indexOf('{'); const last = cleaned.lastIndexOf('}');
  if (first >= 0 && last > first) return JSON.parse(cleaned.slice(first, last + 1));
