const query = $input.first().json.query || {};
const videoRecordId = String(query.video_record_id || '').trim();
if (!videoRecordId) throw new Error('缺少 video_record_id');
const token = await feishuToken();
const queryReferenceUrl = String(query.reference_url || '').trim();
const queryLanguage = String(query.language || '').trim();
const queryPersona = String(query.persona || '').trim();
const queryFinalDialogue = String(query.final_dialogue || '').trim();
const queryExistingImageUrl = String(query.existing_image_url || '').trim();
const queryMode = Boolean(queryReferenceUrl || queryLanguage || queryPersona || queryFinalDialogue || queryExistingImageUrl);
const video = queryMode
  ? { fields: { '产品图URL': urlValue(queryReferenceUrl), '语言': queryLanguage, '达人偏好': queryPersona, 'Veo口播脚本': queryFinalDialogue, 'UGC关键图URL': urlValue(queryExistingImageUrl) } }
  : await getRecord(token, VIDEO_TABLE, videoRecordId);
if (!video) throw new Error('找不到视频任务');
const productId = linkIds(video.fields['关联产品'])[0];
const hookId = linkIds(video.fields['关联Hook'])[0];
const scriptId = linkIds(video.fields['关联脚本'])[0];
const productResult = queryMode ? { record: null, warning: '' } : await optionalRecord(token, PRODUCT_TABLE, productId, '产品');
const hookResult = queryMode ? { record: null, warning: '' } : await optionalRecord(token, HOOK_TABLE, hookId, 'Hook');
const scriptResult = queryMode ? { record: null, warning: '' } : await optionalRecord(token, SCRIPT_TABLE, scriptId, '脚本');
const product = productResult.record || { fields: {} };
const hook = hookResult.record || { fields: {} };
const script = scriptResult.record || { fields: {} };
const warnings = [productResult.warning, hookResult.warning, scriptResult.warning].filter(Boolean);
const referenceUrl = urlCell(video.fields['产品图URL']) || urlCell(product.fields['产品主图URL']);
if (!referenceUrl) throw new Error('缺少产品图 URL。请在视频任务里填写产品图URL，或确保产品主图URL存在。');
const language = firstSelect(video.fields['语言']) || '中文';
const finalDialogue = textCell(video.fields['Veo口播脚本']);
const existingImageUrl = urlCell(video.fields['UGC关键图URL']);
const existingImageTaskId = textCell(video.fields['KIE图片任务ID']);
await updateRecord(token, VIDEO_TABLE, videoRecordId, { '视频状态': '生成关键图中', '错误信息': warnings.length ? ('上下文记录读取不完整，已使用视频任务字段继续生成：' + warnings.join('；')) : '' });
const confirmedScript = finalDialogue || (language === '英文' ? textCell(script.fields['完整脚本_en']) : textCell(script.fields['完整脚本_zh']));
const productBrief = { ...productBriefFromFields(product.fields), source_url: urlCell(product.fields['产品链接']) || urlCell(video.fields['产品链接']) };
if (!productBrief.product_name) productBrief.product_name = 'the product shown in the reference image';
if (!productBrief.core_selling_points) productBrief.core_selling_points = confirmedScript || 'UGC product recommendation based on the confirmed short dialogue';
if (!productBrief.target_audience) productBrief.target_audience = textCell(video.fields['达人偏好']) || 'UGC audience';
const feishuBrief = {
  video_task: { language, reference_url: referenceUrl, persona_preference: textCell(video.fields['达人偏好']), final_dialogue: finalDialogue },
  script: { script_zh: textCell(script.fields['完整脚本_zh']), script_en: textCell(script.fields['完整脚本_en']), cta_zh: textCell(script.fields['CTA_zh']), cta_en: textCell(script.fields['CTA_en']) },
  hook: { hook_concept: textCell(hook.fields['Hook概念']), visual_hook: textCell(hook.fields['视觉开场']), hook_category: firstSelect(hook.fields['Hook分类']) },
  product: productBrief,
  reference_policy: { selected_source: '产品图URL', task_reference_url: referenceUrl },
  context_warnings: warnings,
};
return [{ json: { videoRecordId, productId, hookId, scriptId, referenceUrl, language, finalDialogue, confirmedScript, existingImageUrl, existingImageTaskId, feishuBrief } }];

