const kieKey = String($env.KIE_API_KEY || '').trim();
if (!kieKey) throw new Error('KIE_API_KEY 未配置。');
const token = await feishuToken();
if (prep.existingImageUrl) {
  await updateRecord(token, VIDEO_TABLE, prep.videoRecordId, { '视频状态': '生成视频中', 'UGC场景JSON': JSON.stringify(ugcRow, null, 2), 'UGC图片Prompt': imagePrompt, 'Veo口播脚本': ugcRow.ShortDialogue || prep.finalDialogue || '' });
