  body: { model: 'gpt-image-2-image-to-image', input: { prompt: imagePrompt, input_urls: [prep.referenceUrl], aspect_ratio: '9:16' } },
}, 'KIE GPT Image 2 create');
const imageTaskId = imgTask?.data?.taskId;
