const hookResult = queryMode ? { record: null, warning: '' } : await optionalRecord(token, HOOK_TABLE, hookId, 'Hook');
const scriptResult = queryMode ? { record: null, warning: '' } : await optionalRecord(token, SCRIPT_TABLE, scriptId, '脚本');
