function chainText(input) { return String(input?.text || input?.output || input?.response || '').trim(); }
async function sleep(ms) { return new Promise((resolve) => setTimeout(resolve, ms)); }
function parseJson(input) {
  if (input && typeof input === 'object' && !input.text && !input.output) return input;
  const raw = String(input?.text || input?.output || input?.response || '');
  const cleaned = raw.replace(/^\s*\`\`\`(?:json)?/i, '').replace(/\`\`\`\s*$/i, '').trim();
  try { return JSON.parse(cleaned); } catch {}
  const first = cleaned.indexOf('{'); const last = cleaned.lastIndexOf('}');
  if (first >= 0 && last > first) return JSON.parse(cleaned.slice(first, last + 1));
  throw new Error('无法解析 JSON: ' + cleaned.slice(0, 500));
}

const item = $input.first().json;
const kieKey = String($env.KIE_API_KEY || '').trim();
const token = await feishuToken();
const pollCount = Number(item.videoPollCount || 0) + 1;
const res = item.videoProvider === 'seedance'
  ? await requestJson({ method: 'GET', url: 'https://api.kie.ai/api/v1/jobs/recordInfo?taskId=' + encodeURIComponent(item.videoTaskId), headers: { Authorization: 'Bearer ' + kieKey } }, 'KIE Seedance poll')
  : await requestJson({ method: 'GET', url: 'https://api.kie.ai/api/v1/veo/record-info', headers: { Authorization: 'Bearer ' + kieKey }, qs: { taskId: item.videoTaskId } }, 'KIE Veo poll');
const data = res?.data || {};
if (data.state === 'fail' || data.errorMessage || data.failMsg) {
  const msg = '视频生成失败: ' + item.videoTaskId + ' / ' + (data.errorMessage || data.failMsg || 'unknown');
  await updateRecord(token, VIDEO_TABLE, item.videoRecordId, { '视频状态': '失败', '错误信息': msg });
  throw new Error(msg);
}
const urls = data?.response?.resultUrls || parseResultUrls(data.resultJson);
if ((data.state === 'success' || item.videoProvider === 'veo') && Array.isArray(urls) && urls.length) {
  await updateRecord(token, VIDEO_TABLE, item.videoRecordId, {
    '视频状态': '视频已生成',
    '视频URL': urlValue(String(urls[0])),
    '生成配置': JSON.stringify({ llm_model: 'deepseek-chat', image_model: 'gpt-image-2-image-to-image', video_model: item.videoModel || 'veo3_fast', language: item.language, generate_audio: true, image_task_id: item.imageTaskId, video_task_id: item.videoTaskId, completed_at: new Date().toISOString() }, null, 2),
    '错误信息': '',
  });
  return [{ json: { ...item, videoReady: true, videoUrl: String(urls[0]) } }];
}
if (pollCount >= 60) {
  const msg = 'Veo 超时: ' + item.videoTaskId;
  await updateRecord(token, VIDEO_TABLE, item.videoRecordId, { '视频状态': '失败', '错误信息': msg });
  throw new Error(msg);
}
return [{ json: { ...item, videoReady: false, videoPollCount: pollCount } }];
